mapper.sql:
(
    (lc.model_number IS NOT NULL AND lc.model_number != '' AND lc.model_number = p.model_number)
    OR ((lc.model_number IS  NULL OR lc.model_number = ''  ) AND lc.foil_series = p.name)
)
AND lc.post_processing_step_id = #{params.postProcessingStepId}
AND lc.lamination_material_id = #{params.laminationMaterialId}
AND lc.compatibility IN ('V', '▷')
AND (lc.product_type IS NULL OR lc.product_type = '' OR lc.product_type = p.hot_stamping_paper_type)

AND (p.status IS NULL OR p.status = '可用')
AND (l.company_number ILIKE #{params.companyNumber} OR l.gp_no ILIKE #{params.companyNumber})
AND p.descirption LIKE CONCAT('%', #{params.gpNo}, '%')
AND EXISTS ( SELECT 1 FROM hot_stamping_compatibility hsc WHERE hsc.paper_performance = p.hot_stamping_paper_type AND hsc.product_type_id = #{params.productTypeId} AND hsc.compatibility IN ('V', '▷') )
AND EXISTS ( SELECT 1 FROM hot_stamping_compatibility hsc WHERE hsc.paper_performance = p.hot_stamping_paper_type AND hsc.pattern_characteristic_id = #{params.patternId} AND hsc.compatibility IN ('V', '▷') )
AND p.hot_stamping_paper_type IN
#{hotStampingPaperType}
AND EXISTS ( SELECT 1 FROM cloth_paper_compatibility cpc WHERE cpc.product_name = p.name AND cpc.cloth_paper_type_id = #{params.clothPaperTypeId} AND cpc.compatibility_status = #{params.clothPaperCompatibilityStatus} AND (cpc.paper_type IS NULL OR cpc.paper_type = p.hot_stamping_paper_type) )
AND pr.price = #{params.priceLevel}
AND ( ppp.cloth_paper_type_id = #{params.clothPaperTypeId} AND ppp.compatibility_status IN ('V', '▷') )
AND EXISTS ( SELECT 1 FROM post_processing_leduvglitter ppl_led WHERE (ppl_led.product_model_number IS NOT NULL AND ppl_led.product_model_number = p.model_number OR ppl_led.product_name IS NOT NULL AND ppl_led.product_name = p.name) AND (ppl_led.paper_type IS NULL OR ppl_led.paper_type = '' OR ppl_led.paper_type = p.hot_stamping_paper_type) AND ppl_led.compatibility_status IN ('V', '▷')
AND ppl_led.cloth_paper_type_id = #{params.clothPaperTypeId}
)
AND NOT EXISTS ( SELECT 1 FROM cloth_paper_types cpt_for_uv WHERE cpt_for_uv.id = #{params.clothPaperTypeId} AND cpt_for_uv.disallow_uv_print_with_type = TRUE )
AND EXISTS ( SELECT 1 FROM post_processing_print_uv pppu_uv WHERE ( -- 情况1：仅配置系列 pppu_uv.product_name IS NOT NULL AND pppu_uv.product_name != '' AND (pppu_uv.product_model_number IS NULL OR pppu_uv.product_model_number = '') AND pppu_uv.product_name = p.name ) OR ( -- 情况2：仅配置型号 pppu_uv.product_model_number IS NOT NULL AND pppu_uv.product_model_number != '' AND (pppu_uv.product_name IS NULL OR pppu_uv.product_name = '') AND pppu_uv.product_model_number = p.model_number ) OR ( -- 情况3：系列 + 型号都配置 → 两者都需匹配 pppu_uv.product_model_number IS NOT NULL AND pppu_uv.product_model_number != '' AND pppu_uv.product_name IS NOT NULL AND pppu_uv.product_name != '' AND pppu_uv.product_model_number = p.model_number AND pppu_uv.product_name = p.name ) AND (pppu_uv.paper_type IS NULL OR pppu_uv.paper_type = '' OR pppu_uv.paper_type = p.hot_stamping_paper_type) AND pppu_uv.compatibility_status IN ('V', '▷')
AND pppu_uv.company_number = #{params.companyNumber}
)
AND lc.id IS NOT NULL
AND ( ( EXISTS ( SELECT 1 FROM hot_stamping_compatibility h_exist_emb WHERE h_exist_emb.hot_stamping_type_id = ( SELECT hsto_emb.id FROM hot_stamping_type_options hsto_emb WHERE hsto_emb.stamping_type = '燙金後擊凸' AND hsto_emb.position_type IS NULL ) AND h_exist_emb.compatibility IN ('V', '▷') ) AND EXISTS ( SELECT 1 FROM hot_stamping_compatibility hsc_emb WHERE hsc_emb.hot_stamping_type_id = ( SELECT hsto_emb2.id FROM hot_stamping_type_options hsto_emb2 WHERE hsto_emb2.stamping_type = '燙金後擊凸' AND hsto_emb2.position_type IS NULL ) AND hsc_emb.compatibility IN ('V', '▷') AND hsc_emb.paper_performance = p.hot_stamping_paper_type ) ) OR NOT EXISTS ( SELECT 1 FROM hot_stamping_compatibility h_absent_emb WHERE h_absent_emb.hot_stamping_type_id = ( SELECT hsto_emb3.id FROM hot_stamping_type_options hsto_emb3 WHERE hsto_emb3.stamping_type = '燙金後擊凸' AND hsto_emb3.position_type IS NULL ) AND h_absent_emb.compatibility IN ('V', '▷') ) )
AND ( ( EXISTS ( SELECT 1 FROM hot_stamping_type_options hstoX_emb INNER JOIN hot_stamping_type_options hsto_defaultX_emb ON hsto_defaultX_emb.stamping_type = hstoX_emb.stamping_type AND hsto_defaultX_emb.position_type IS NULL INNER JOIN hot_stamping_type_compatibility hstcX_emb ON hstcX_emb.hot_stamping_type_id = hsto_defaultX_emb.id WHERE hstoX_emb.stamping_type = '燙金後擊凸' AND hstoX_emb.position_type IS NULL AND hstcX_emb.compatibility_status IN ('V', '▷') ) AND EXISTS ( SELECT 1 FROM hot_stamping_type_compatibility hstc_emb INNER JOIN hot_stamping_type_options hsto_emb ON hsto_emb.stamping_type = '燙金後擊凸' AND hsto_emb.position_type IS NULL INNER JOIN hot_stamping_type_options hsto_default_emb ON hsto_default_emb.stamping_type = hsto_emb.stamping_type AND hsto_default_emb.position_type IS NULL WHERE hstc_emb.hot_stamping_type_id = hsto_default_emb.id AND hstc_emb.compatibility_status IN ('V', '▷') AND hstc_emb.product_name = p.name AND (hstc_emb.paper_type IS NULL OR hstc_emb.paper_type = p.hot_stamping_paper_type) ) ) OR NOT EXISTS ( SELECT 1 FROM hot_stamping_type_options hstoX_emb2 INNER JOIN hot_stamping_type_options hsto_defaultX_emb2 ON hsto_defaultX_emb2.stamping_type = hstoX_emb2.stamping_type AND hsto_defaultX_emb2.position_type IS NULL INNER JOIN hot_stamping_type_compatibility hstcX_emb2 ON hstcX_emb2.hot_stamping_type_id = hsto_defaultX_emb2.id WHERE hstoX_emb2.stamping_type = '燙金後擊凸' AND hstoX_emb2.position_type IS NULL AND hstcX_emb2.compatibility_status IN ('V', '▷') ) )
AND EXISTS ( SELECT 1 FROM hot_stamping_type_compatibility hstc INNER JOIN hot_stamping_type_options hsto ON hsto.id = #{params.hotStampingTypeOptionId} INNER JOIN hot_stamping_type_options hsto_default ON hsto_default.stamping_type = hsto.stamping_type AND hsto_default.position_type IS NULL WHERE hstc.hot_stamping_type_id = hsto_default.id AND hstc.compatibility_status IN ('V', '▷') AND hstc.product_name = p.name AND (hstc.paper_type IS NULL OR hstc.paper_type = p.hot_stamping_paper_type) )
AND EXISTS ( SELECT 1 FROM hot_stamping_patternx_area_compatibility hspac WHERE hspac.hot_stamping_patternx_area_id = #{params.patternAreaOptionId} AND hspac.compatibility_status IN ('V', '▷') AND hspac.product_name = p.name AND (hspac.paper_type IS NULL OR hspac.paper_type = p.hot_stamping_paper_type) )
AND p.paizi = #{params.paizi}
AND s.color_num = #{params.colorNum}
